mapper.select:
SELECT id, parent_id AS parentId, category_name AS categoryName, category_code AS categoryCode, description, icon, sort_order AS sortOrder, status, created_time AS createdTime FROM course_category
AND category_name LIKE CONCAT('%', #{q.categoryName}, '%')
AND status = #{q.status}
AND parent_id = #{q.parentId}
ORDER BY sort_order ASC, id ASC
